package com.demo.web.dto.Events;

public class EventVoteDataRequest { private int userId; private String eventIdStr; private String groupIdStr; private String typeStr; public EventVoteDataRequest(int userId, String eventIdStr, String groupIdStr, String typeStr) { this.userId = userId; this.eventIdStr = eventIdStr; this.groupIdStr = groupIdStr; this.typeStr = typeStr; } public int getUserId() { return userId; } public void setUserId(int userId) { this.userId = userId; } public String getEventIdStr() { return eventIdStr; } public void setEventIdStr(String eventIdStr) { this.eventIdStr = eventIdStr; } public String getGroupIdStr() { return groupIdStr; } public void setGroupIdStr(String groupIdStr) { this.groupIdStr = groupIdStr; } public String getTypeStr() { return typeStr; } public void setTypeStr(String typeStr) { this.typeStr = typeStr; } }
